document.addEventListener("DOMContentLoaded",(()=>{fetch("../assets/data/trip.json").then((e=>e.json())).then((e=>{const n=document.querySelector("main"),t=document.createElement("div");t.classList.add("header"),t.innerHTML=`<h1>${e.title}</h1>`,n.appendChild(t),e.days.forEach((e=>{const t=document.createElement("div");t.classList.add("day");const d=document.createElement("h2");d.classList.add("day-header"),d.innerText=e.day,t.appendChild(d);const i=document.createElement("div");i.classList.add("day-content"),e.checkpoints.forEach((e=>{const n=document.createElement("div");n.classList.add("day-content-checkpoint"),e.class&&n.classList.add(e.class),n.innerHTML=`\n            <div class="day-content-checkpoint-timeline">\n              <div class="day-content-checkpoint-timeline-time">${e.time}</div>\n              <div class="day-content-checkpoint-timeline-line"></div>\n            </div>\n            <div class="day-content-checkpoint-info">\n              <div class="day-content-checkpoint-info-title">\n                ${e.icon?`<i class="fa-solid ${e.icon}"></i>`:""} ${e.title}\n              </div>\n              <div class="day-content-checkpoint-info-description">${e.description}</div>\n            </div>\n          `,i.appendChild(n)})),t.appendChild(i),n.appendChild(t),d.addEventListener("click",(()=>{i.classList.toggle("expanded")}))}))})).catch((e=>console.error("Error loading itinerary:",e)))}));